        // 2. 执行同步
        val syncResult = syncHelper.sync(uniqueEvents, targetCalendar)

        // 3. 返回结果
        return syncResult.copy(
            originalCount = events.size,
            uniqueCount = uniqueEvents.size
        )
    }

    /**
     * 创建新的日历事件
     * @param title 事件标题
     * @param description 事件描述
     * @param startTime 开始时间
     * @param endTime 结束时间
     * @param location 位置
     * @return 构建的事件
     */
    fun createEvent(
        title: String,
        description: String = "",
        startTime: Date,
