        return CalendarEventBuilder()
            .setTitle(title)
            .setDescription(description)
            .setStartTime(startTime)
            .setEndTime(endTime)
            .setLocation(location)
            .build()
    }

    /**
     * 获取指定时间范围内的事件
     * @param startTime 开始时间
     * @param endTime 结束时间
     * @return 事件列表
     */
