package courtassistant.calendar

import courtassistant.calendar.model.CalendarEvent
import java.util.Calendar
import java.util.Date

/**
 * 日历事件构建器 - 使用建造者模式创建事件对象
 */
class CalendarEventBuilder {
    private var title: String = ""
    private var description: String = ""
    private var startTime: Date? = null
    private var endTime: Date? = null
    private var location: String = ""
    private var reminderMinutes: Int = 15
    private var isAllDay: Boolean = false

    /**
     * 设置事件标题
     */
    fun setTitle(title: String): CalendarEventBuilder {
        this.title = title
        return this
    }

    /**
     * 设置事件描述
     */
    fun setDescription(description: String): CalendarEventBuilder {
        this.description = description
        return this
    }

    /**
     * 设置开始时间
     */
    fun setStartTime(startTime: Date): CalendarEventBuilder {
        this.startTime = startTime
        return this
    }

    /**
     * 设置结束时间
     */
    fun setEndTime(endTime: Date): CalendarEventBuilder {
        this.endTime = endTime
        return this
    }

    /**
     * 设置位置
     */
    fun setLocation(location: String): CalendarEventBuilder {
        this.location = location
        return this
    }

    /**
     * 设置提醒时间（分钟）
     */
    fun setReminderMinutes(minutes: Int): CalendarEventBuilder {
        this.reminderMinutes = minutes
        return this
    }

    /**
     * 设置为全天事件
     */
    fun setAllDay(allDay: Boolean): CalendarEventBuilder {
        this.isAllDay = allDay
        return this
    }

    /**
     * 构建日历事件
     * @return 构建完成的日历事件
     * @throws IllegalArgumentException 如果缺少必要信息
     */
    fun build(): CalendarEvent {
        // 验证必要信息
        if (title.isBlank()) {
            throw IllegalArgumentException("事件标题不能为空")
        }

        if (startTime == null) {
            throw IllegalArgumentException("开始时间不能为空")
        }

        // 如果是全天事件，结束时间应该为次日
        var calculatedEndTime = endTime ?: run {
            val calendar = Calendar.getInstance().apply {
                time = startTime!!
                add(Calendar.DAY_OF_MONTH, 1)
            }
            calendar.time
        }

        return CalendarEvent(
            id = generateId(),
            title = title,
            description = description,
            startTime = startTime!!,
            endTime = calculatedEndTime,
            location = location,
            reminderMinutes = reminderMinutes,
            isAllDay = isAllDay
        )
    }

    /**
     * 生成唯一的事件ID
     */
    private fun generateId(): String {
        return "event_${System.currentTimeMillis()}_${title.hashCode().toString(16)}"
    }
}

