import courtassistant.calendar.model.CalendarEvent
import courtassistant.calendar.model.DedupKey
import java.util.Date

/**
 * 去重助手 - 负责处理日历事件去重逻辑
 */
class DedupHelper {
    /**
     * 对事件列表进行去重
     * @param events 原始事件列表
     * @return 去重后的事件列表
     */
    fun deduplicate(events: List<CalendarEvent>): List<CalendarEvent> {
        val seenKeys = mutableSetOf<DedupKey>()
        val deduplicatedEvents = mutableListOf<CalendarEvent>()

        events.forEach { event ->
            val dedupKey = generateDedupKey(event)

            if (!seenKeys.contains(dedupKey)) {
                seenKeys.add(dedupKey)
                deduplicatedEvents.add(event)
            }
        }

        return deduplicatedEvents
    }

    /**
     * 检查事件是否重复
     * @param event 待检查的事件
     * @param existingEvents 已存在的事件列表
     * @return 是否重复
     */
    fun isDuplicate(event: CalendarEvent, existingEvents: List<CalendarEvent>): Boolean {
        val dedupKey = generateDedupKey(event)
        return existingEvents.any { existing ->
            generateDedupKey(existing) == dedupKey
        }
    }

    /**
     * 获取重复事件
     * @param events 事件列表
     * @return 重复事件列表
     */
    fun getDuplicateEvents(events: List<CalendarEvent>): List<CalendarEvent> {
        val seen = mutableSetOf<DedupKey>()
        val duplicates = mutableListOf<CalendarEvent>()

        events.forEach { event ->
            val dedupKey = generateDedupKey(event)
            if (!seen.add(dedupKey) && !duplicates.contains(event)) {
                duplicates.add(event)
            }
        }

        return duplicates
    }

    /**
     * 生成去重键
     * @param event 日历事件
     * @return 去重键
     */
    private fun generateDedupKey(event: CalendarEvent): DedupKey {
        // 标准化日期比较（忽略毫秒）
        val normalizedStart = Date(event.startTime.time / 1000 * 1000)
        val normalizedEnd = Date(event.endTime.time / 1000 * 1000)

        // 模糊比较时间（允许5分钟的时间差）
        val toleranceMinutes = 5
        val toleranceMillis = toleranceMinutes * 60 * 1000L

        return DedupKey(
            title = event.title,
            startTime = normalizedStart,
            endTime = normalizedEnd,
            location = event.location,
            toleranceMillis = toleranceMillis
        )
    }

    /**
     * 设置自定义去重策略
     * @param strategy 自定义策略
     */
    fun setDedupStrategy(strategy: (CalendarEvent) -> DedupKey) {
        // 可以扩展为支持自定义去重策略
        throw UnsupportedOperationException("自定义去重策略尚未实现")
    }
}

package courtassistant.calendar.model

import java.io.Serializable
import java.util.Date

/**
 * 日历事件数据模型
 */
data class CalendarEvent(
    val id: String,                    // 事件唯一标识
    val title: String,                 // 事件标题
    val description: String,           // 事件描述
    val startTime: Date,               // 开始时间
    val endTime: Date,                 // 结束时间
    val location: String,             // 事件位置
    val reminderMinutes: Int = 15,     // 提前提醒时间（分钟）
    val isAllDay: Boolean = false,     // 是否为全天事件
    val attendees: List<String> = emptyList(), // 参与者列表
    val calendarId: String = ""        // 所属日历ID
) : Serializable {

    /**
     * 获取事件持续时间（分钟）
     */
    fun getDurationMinutes(): Long {
        return (endTime.time - startTime.time) / (60 * 1000)
    }

    /**
     * 获取事件持续时间（小时）
     */
    fun getDurationHours(): Double {
        return getDurationMinutes() / 60.0
    }

    /**
     * 检查事件是否在指定时间范围内
     */
    fun isInRange(startTime: Date, endTime: Date): Boolean {
        return !this.startTime.after(endTime) && !this.endTime.before(startTime)
    }

    /**
     * 创建事件副本
     */
    fun copy(
        id: String = this.id,
        title: String = this.title,
        description: String = this.description,
        startTime: Date = this.startTime,
        endTime: Date = this.endTime,
        location: String = this.location,
        reminderMinutes: Int = this.reminderMinutes,
        isAllDay: Boolean = this.isAllDay,
        attendees: List<String> = this.attendees,
        calendarId: String = this.calendarId
    ): CalendarEvent {
        return CalendarEvent(
            id = id,
            title = title,
            description = description,
            startTime = startTime,
            endTime = endTime,
            location = location,
            reminderMinutes = reminderMinutes,
            isAllDay = isAllDay,
            attendees = attendees,
            calendarId = calendarId
        )
    }

    companion object {
        /**
         * 创建简单的日历事件
         */
        fun createSimple(
            title: String,
            startTime: Date,
            endTime: Date,
            description: String = ""
        ): CalendarEvent {
            return CalendarEvent(
                id = "simple_${System.currentTimeMillis()}",
                title = title,
                description = description,
                startTime = startTime,
                endTime = endTime,
                location = ""
            )
        }
    }
}

package courtassistant.calendar.model

import java.io.Serializable
import java.util.Date

/**
 * 同步结果数据模型
 */
data class SyncResult(
    val successCount: Int,              // 成功同步数量
    val failCount: Int,                // 失败同步数量
    val originalCount: Int = 0,         // 原始事件总数
    val uniqueCount: Int = 0,          // 去重后事件数量
    val errorMessages: List<String> = emptyList(), // 错误信息列表
    val syncTime: Date = Date(),       // 同步时间
    val duration: Long = 0,            // 同步耗时（毫秒）
    val details: Map<String, Any> = emptyMap() // 附加信息
) : Serializable {

    /**
     * 获取成功率
     */
    fun getSuccessRate(): Double {
        val total = successCount + failCount
        return if (total > 0) {
            successCount.toDouble() / total
        } else {
            0.0
        }
    }

    /**
     * 获取平均处理时间
     */
    fun getAverageDuration(): Double {
        return if (successCount > 0) {
            duration.toDouble() / successCount
        } else {
            0.0
        }
    }

    /**
     * 是否全部同步成功
     */
    fun isAllSuccess(): Boolean {
        return failCount == 0
    }

    /**
     * 是否存在错误
     */
    fun hasErrors(): Boolean {
        return errorMessages.isNotEmpty()
    }

    /**
     * 获取错误消息摘要
     */
    fun getErrorSummary(): String {
        if (errorMessages.isEmpty()) {
            return "无错误"
        }
        return "共有 ${errorMessages.size} 个错误"
    }

    /**
     * 创建结果副本
     */
    fun copy(
        successCount: Int = this.successCount,
        failCount: Int = this.failCount,
        originalCount: Int = this.originalCount,
        uniqueCount: Int = this.uniqueCount,
        errorMessages: List<String> = this.errorMessages,
        syncTime: Date = this.syncTime,
        duration: Long = this.duration,
        details: Map<String, Any> = this.details
    ): SyncResult {
        return SyncResult(
            successCount = successCount,
            failCount = failCount,
            originalCount = originalCount,
            uniqueCount = uniqueCount,
            errorMessages = errorMessages,
            syncTime = syncTime,
            duration = duration,
            details = details
        )
    }

    /**
     * 构建同步报告
     */
    fun buildReport(): String {
        return """
            ===== 同步报告 =====
            原始事件数: $originalCount
            去重后事件数: $uniqueCount
            成功同步: $successCount
            失败同步: $failCount
            成功率: ${String.format("%.2f%%", getSuccessRate() * 100)}
            同步时间: $syncTime
            耗时: ${duration}ms
            $getErrorSummary
        """.trimIndent()
    }
}

