import java.io.Serializable
import java.util.Date

/**
 * 日历事件去重键
 */
data class DedupKey(
    val title: String,          // 事件标题
    val startTime: Date,        // 开始时间
    val endTime: Date,          // 结束时间
    val location: String,      // 事件位置
    val toleranceMillis: Long = 5 * 60 * 1000L // 容忍时间差（毫秒）
) : Serializable {

    /**
     * 创建模糊去重键（忽略时间差）
     */
    fun createFuzzyKey(): DedupKey {
        // 将时间对齐到容忍范围内的整点
        val alignedStartTime = alignToTolerance(startTime, toleranceMillis)
        val alignedEndTime = alignToTolerance(endTime, toleranceMillis)

        return copy(
            startTime = alignedStartTime,
            endTime = alignedEndTime
        )
    }

    /**
     * 检查两个事件键是否重复（考虑容忍时间）
     */
    fun isDuplicate(other: DedupKey): Boolean {
        // 标题相同
        if (title != other.title) return false

        // 位置相同
        if (location != other.location) return false

        // 时间重叠或接近
        val startDiff = Math.abs(startTime.time - other.startTime.time)
        val endDiff = Math.abs(endTime.time - other.endTime.time)

        return startDiff <= toleranceMillis && endDiff <= toleranceMillis
    }

    /**
     * 对齐时间到容忍范围内的整点
     */
    private fun alignToTolerance(date: Date, tolerance: Long): Date {
        val millis = date.time
        val alignedMillis = (millis / tolerance) * tolerance
        return Date(alignedMillis)
    }

    companion object {
        /**
         * 标准化日期比较
         */
        fun normalizeForComparison(date: Date, toleranceMillis: Long): Date {
            val millis = date.time / toleranceMillis * toleranceMillis
            return Date(millis)
        }
    }
}

/**
 * 扩展函数：检查CalendarEvent是否重复
 */
fun CalendarEvent.isDuplicate(other: CalendarEvent, toleranceMinutes: Int = 5): Boolean {
    val toleranceMillis = toleranceMinutes * 60 * 1000L
    val dedupKey = DedupKey(
        title = this.title,
        startTime = this.startTime,
        endTime = this.endTime,
        location = this.location,
        toleranceMillis = toleranceMillis
    )
    val otherDedupKey = DedupKey(
        title = other.title,
        startTime = other.startTime,
        endTime = other.endTime,
        location = other.location,
        toleranceMillis = toleranceMillis
    )

    return dedupKey.isDuplicate(otherDedupKey)
}

/**
 * 扩展函数：获取事件的去重键
 */
fun CalendarEvent.getDedupKey(toleranceMinutes: Int = 5): DedupKey {
    val toleranceMillis = toleranceMinutes * 60 * 1000L
    return DedupKey(
