package courtassistant.calendar.model

import java.io.Serializable
import java.util.Date

/**
 * 日历事件去重键 - 用于判断事件是否重复
 */
data class DedupKey(
    val title: String,                    // 事件标题
    val startTime: Date,                  // 开始时间
    val endTime: Date,                    // 结束时间
    val location: String,                  // 事件位置
    val toleranceMillis: Long = 5 * 60 * 1000L // 时间容差（5分钟）
) : Serializable {

    /**
     * 检查与另一个去重键是否匹配（考虑容差）
     */
    fun matches(other: DedupKey): Boolean {
        if (title != other.title) return false
        if (location != other.location) return false

        // 检查时间范围是否重叠（考虑容差）
        val startDiff = Math.abs(startTime.time - other.startTime.time)
        val endDiff = Math.abs(endTime.time - other.endTime.time)

        return startDiff <= toleranceMillis && endDiff <= toleranceMillis
    }

    /**
     * 生成去重键的哈希码
     */
    override fun hashCode(): Int {
        var result = title.hashCode()
        result = 31 * result + startTime.hashCode()
        result = 31 * result + endTime.hashCode()
        result = 31 * result + location.hashCode()
        result = 31 * result + toleranceMillis.hashCode()
        return result
    }

    /**
     * 比较两个去重键是否相等
     */
    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is DedupKey) return false

        return matches(other)
    }

    /**
     * 获取去重键的字符串表示
     */
    override fun toString(): String {
        return "DedupKey(title='$title', startTime=$startTime, endTime=$endTime, location='$location')"
    }

    companion object {
        /**
         * 标准化的去重键生成器（忽略毫秒）
         */
        fun createNormalized(event: CalendarEvent, toleranceMinutes: Int = 5): DedupKey {
            // 标准化日期比较（忽略毫秒）
            val normalizedStart = Date(event.startTime.time / 1000 * 1000)
            val normalizedEnd = Date(event.endTime.time / 1000 * 1000)

            // 转换容差时间为毫秒
            val toleranceMillis = toleranceMinutes * 60 * 1000L

            return DedupKey(
                title = event.title,
                startTime = normalizedStart,
                endTime = normalizedEnd,
                location = event.location,
                toleranceMillis = toleranceMillis
            )
        }

        /**
         * 简单的去重键生成器（仅标题和时间）
         */
        fun createSimple(event: CalendarEvent, toleranceMinutes: Int = 5): DedupKey {
            val toleranceMillis = toleranceMinutes * 60 * 1000L

            // 简化时间比较（仅比较小时和分钟）
            val startCalendar = java.util.Calendar.getInstance().apply { time = event.startTime }
            val endCalendar = java.util.Calendar.getInstance().apply { time = event.endTime }

            return DedupKey(
                title = event.title,
                startTime = event.startTime,
                endTime = event.endTime,
                location = "",
                toleranceMillis = toleranceMillis
            )
        }
    }
}
